import json
with open('/Users/bhyslop/projects/rbm_alpha_recipemuster/.claude/jjm/jjg_gallops.json') as f:
    data = json.load(f)

import re

# Search for RBSA (not RBSAA or similar), JJSA, BUSA, VOS- or VOS (not VOS followed by letter)
patterns = {
    'RBSA': re.compile(r'RBSA(?![A-Z])'),  # RBSA not followed by uppercase
    'JJSA': re.compile(r'JJSA'),
    'BUSA': re.compile(r'BUSA'),
    'VOS': re.compile(r'VOS(?![A-Za-z_])'),  # VOS not followed by letter or underscore
}

results = []

for heat_id, heat in data.get('heats', {}).items():
    # Check paddock
    paddock = heat.get('paddock', '')
    for pat_name, pat in patterns.items():
        if pat.search(paddock):
            results.append(f'PADDOCK heat={heat_id} pattern={pat_name} field=paddock')

    # Check paces
    for pace_id, pace in heat.get('paces', {}).items():
        for tack in pace.get('tacks', []):
            state = tack.get('state', '')
            text = tack.get('text', '')
            direction = tack.get('direction', '')
            silks = tack.get('silks', '')

            for pat_name, pat in patterns.items():
                found_in = []
                if pat.search(text):
                    found_in.append('text')
                if pat.search(direction):
                    found_in.append('direction')
                if pat.search(silks):
                    found_in.append('silks')
                if found_in:
                    results.append(f'PACE heat={heat_id} pace={pace_id} state={state} pattern={pat_name} fields={\",\".join(found_in)}')

for r in results:
    print(r)
